module timer_regs #(
    parameter integer DATA_WIDTH = 32,
    parameter integer ADDR_WIDTH = 4
) (
    input  logic                  pclk,
    input  logic                  presetn,
    input  logic [ADDR_WIDTH-1:0] paddr,
    input  logic                  psel,
    input  logic                  penable,
    input  logic                  pwrite,
    input  logic [DATA_WIDTH-1:0] pwdata,
    input  logic [DATA_WIDTH-1:0] count_q,
    output logic [DATA_WIDTH-1:0] prdata,
    output logic                  pready,
    output logic                  pslverr,
    output logic [DATA_WIDTH-1:0] load_q,
    output logic                  enable_q,
    output logic                  irq_q
);
    localparam [ADDR_WIDTH-1:0] ADDR_LOAD   = 4'h0;
    localparam [ADDR_WIDTH-1:0] ADDR_CTRL   = 4'h4;
    localparam [ADDR_WIDTH-1:0] ADDR_STATUS = 4'h8;
    localparam [DATA_WIDTH-1:0] CTRL_RESERVED_MASK = {DATA_WIDTH{1'b1}} & ~{{(DATA_WIDTH-1){1'b0}}, 1'b1};

    logic apb_access;
    logic apb_valid_write;
    logic apb_valid_read;
    logic legal_addr;
    logic wr_load;
    logic rd_load;
    logic wr_ctrl;
    logic rd_ctrl;
    logic wr_status;
    logic rd_status;
    logic tick_idle;
    logic tick_decrement;
    logic tick_reload;
    logic tick_disabled;
    logic irq_decrement;
    logic irq_reload;
    logic [DATA_WIDTH-1:0] read_mux;
    logic [DATA_WIDTH-1:0] ctrl_read_data;
    logic [DATA_WIDTH-1:0] ctrl_reserved_zero;
    logic [DATA_WIDTH-1:0] count_decrement_value;
    logic [DATA_WIDTH-1:0] reload_count_value;

    assign apb_access      = psel & penable;
    assign apb_valid_write = apb_access & pwrite;
    assign apb_valid_read  = apb_access & (~pwrite);
    assign legal_addr      = (paddr == ADDR_LOAD) | (paddr == ADDR_CTRL) | (paddr == ADDR_STATUS);
    assign wr_load         = apb_valid_write & (paddr == ADDR_LOAD);
    assign rd_load         = apb_valid_read  & (paddr == ADDR_LOAD);
    assign wr_ctrl         = apb_valid_write & (paddr == ADDR_CTRL);
    assign rd_ctrl         = apb_valid_read  & (paddr == ADDR_CTRL);
    assign wr_status       = apb_valid_write & (paddr == ADDR_STATUS);
    assign rd_status       = apb_valid_read  & (paddr == ADDR_STATUS);

    assign tick_idle       = ~psel;
    assign tick_decrement  = tick_idle & enable_q & (count_q != {DATA_WIDTH{1'b0}});
    assign tick_reload     = tick_idle & enable_q & (count_q == {DATA_WIDTH{1'b0}});
    assign tick_disabled   = tick_idle & (~enable_q);
    assign irq_decrement   = tick_decrement & 1'b0;
    assign irq_reload      = tick_reload;

    assign count_decrement_value = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
    assign reload_count_value    = load_q;

    // CTRL.RESERVED is read-only zero and ignores writes; masking documents the legal
    // bit 0 ENABLE field while upper byte lanes/reserved bits remain non-error inputs.
    assign ctrl_reserved_zero = pwdata & CTRL_RESERVED_MASK & {DATA_WIDTH{1'b0}};
    assign ctrl_read_data     = ctrl_reserved_zero | {{(DATA_WIDTH-1){1'b0}}, enable_q};

    always @(*) begin
        read_mux = {DATA_WIDTH{1'b0}};
        if (rd_load) begin
            read_mux = load_q;
        end else if (rd_ctrl) begin
            read_mux = ctrl_read_data;
        end else if (rd_status) begin
            read_mux = count_q;
        end else begin
            read_mux = {DATA_WIDTH{1'b0}};
        end
    end

    always @(*) begin
        pready  = apb_access;
        pslverr = apb_access & (~legal_addr);
        prdata  = read_mux;
    end

    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            load_q   <= {DATA_WIDTH{1'b0}};
            enable_q <= 1'b0;
            irq_q    <= 1'b0;
        end else begin
            irq_q <= 1'b0;

            if (wr_load) begin
                load_q <= pwdata;
            end

            if (wr_ctrl) begin
                enable_q <= pwdata[0];
            end

            if (wr_status) begin
                irq_q <= 1'b0;
            end else if (tick_decrement) begin
                irq_q <= irq_decrement;
            end else if (tick_reload) begin
                irq_q <= irq_reload;
            end else if (tick_disabled) begin
                irq_q <= 1'b0;
            end else begin
                irq_q <= 1'b0;
            end
        end
    end

endmodule

